const pedidos = $input.all();

const hoy = new Date().toISOString().split('T')[0];

const pedidosHoy = pedidos.filter(p => p.json.fecha === hoy);

if (pedidosHoy.length === 0) {
  return [{
    json: {
      hay_pedidos: false,
      mensaje: `📊 Reporte Diario — ${hoy}\n\n⚠️ No hubo pedidos hoy.`
    }
  }];
}

const totalVendido = pedidosHoy.reduce((sum, p) => {
  return sum + Number(p.json.total_pagar || 0);
}, 0);

const conteoProductos = {};
pedidosHoy.forEach(p => {
  const detalle = p.json.detalle_pedido || '';
  const items = detalle.split(' | ');
  items.forEach(item => {
    const partes = item.trim().split(' x');
    if (partes.length >= 2) {
      const nombre = partes[0].trim();
      const cantidad = Number(partes[1]) || 1;
      conteoProductos[nombre] = (conteoProductos[nombre] || 0) + cantidad;
    }
  });
});

const productoEstrella = Object.entries(conteoProductos)
  .sort((a, b) => b[1] - a[1])[0];

const conteoPorHora = {};
pedidosHoy.forEach(p => {
  const horaRaw = (p.json.hora || '00:00:00').split(':')[0].padStart(2, '0');
  const hora = horaRaw + ':00';
  conteoPorHora[hora] = (conteoPorHora[hora] || 0) + 1;
});

const horaPico = Object.entries(conteoPorHora)
  .sort((a, b) => b[1] - a[1])[0];

const mensaje = `📊 Reporte Diario — ${hoy}\n\n💰 Total vendido: $${totalVendido}\n📦 Pedidos procesados: ${pedidosHoy.length}\n⭐ Producto estrella: ${productoEstrella ? `${productoEstrella[0]} (${productoEstrella[1]} unidades)` : 'N/A'}\n⏰ Hora pico: ${horaPico ? `${horaPico[0]} (${horaPico[1]} pedido)` : 'N/A'}\n\nGenerado automáticamente por DeliveryBot`;

return [{
  json: {
    hay_pedidos: true,
    mensaje: mensaje,
    total_vendido: totalVendido,
    pedidos_hoy: pedidosHoy.length,
    producto_estrella: productoEstrella?.[0] || 'N/A',
    hora_pico: horaPico?.[0] || 'N/A'
  }
}];
